import os
import time
from typing import Optional

from flask import Flask, request, Response
from prometheus_client import (
    CollectorRegistry,
    Counter,
    generate_latest,
    CONTENT_TYPE_LATEST,
)

APP_NAME = os.getenv("APP_NAME", "traffic_analyzer")
METRICS_PATH = os.getenv("METRICS_PATH", "/metrics")
HOST = os.getenv("HOST", "0.0.0.0")
PORT = int(os.getenv("PORT", "8000"))

# WARNING: This design creates a new Prometheus time series per unique label set.
# High-cardinality labels (user_id, session_id, full path) can exhaust memory and
# overload Prometheus. Use only if you fully control cardinality and retention.

registry = CollectorRegistry(auto_describe=True)

http_requests_total = Counter(
    "http_requests_total",
    "Total HTTP requests",
    labelnames=("user_id", "session_id", "path", "method", "status"),
    registry=registry,
)

http_request_duration_seconds = Counter(
    "http_request_duration_seconds_total",
    "Total accumulated HTTP request duration in seconds (counter)",
    labelnames=("user_id", "session_id", "path", "method", "status"),
    registry=registry,
)

# Tracks unique user-path combinations observed (one series per combination).
unique_user_path_total = Counter(
    "unique_user_path_total",
    "Marks that a unique (user_id, path) combination has been seen (counter increments once per unique pair)",
    labelnames=("user_id", "path"),
    registry=registry,
)

_seen_user_path = set()

app = Flask(__name__)


def _get_user_id() -> str:
    return (
        request.headers.get("X-User-Id")
        or request.args.get("user_id")
        or "anonymous"
    )


def _get_session_id() -> str:
    return (
        request.headers.get("X-Session-Id")
        or request.cookies.get("session_id")
        or request.args.get("session_id")
        or "none"
    )


def _full_path() -> str:
    # full_path includes query string; "full request path" interpreted as path + query.
    # If you want only URL path without query, use request.path.
    fp = request.full_path
    if fp.endswith("?"):
        fp = fp[:-1]
    return fp


@app.before_request
def _before_request():
    request._start_time = time.perf_counter()


@app.after_request
def _after_request(response: Response):
    try:
        user_id = _get_user_id()
        session_id = _get_session_id()
        path = _full_path()
        method = request.method
        status = str(response.status_code)

        http_requests_total.labels(
            user_id=user_id,
            session_id=session_id,
            path=path,
            method=method,
            status=status,
        ).inc()

        duration = max(0.0, time.perf_counter() - getattr(request, "_start_time", time.perf_counter()))
        http_request_duration_seconds.labels(
            user_id=user_id,
            session_id=session_id,
            path=path,
            method=method,
            status=status,
        ).inc(duration)

        key = (user_id, path)
        if key not in _seen_user_path:
            _seen_user_path.add(key)
            unique_user_path_total.labels(user_id=user_id, path=path).inc()
    except Exception:
        pass

    return response


@app.route(METRICS_PATH, methods=["GET"])
def metrics():
    data = generate_latest(registry)
    return Response(data, mimetype=CONTENT_TYPE_LATEST)


@app.route("/", defaults={"path": ""}, methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS", "HEAD"])
@app.route("/<path:path>", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS", "HEAD"])
def catch_all(path: str):
    return Response("ok", status=200, mimetype="text/plain")


if __name__ == "__main__":
    app.run(host=HOST, port=PORT)